}

function StatBox({ icon, label, value, change }: { icon: React.ReactNode; label: string; value: string; change: number }) {
  return (
    <div className="card p-4">
      <div className="flex items-center gap-2 text-sm text-text-light-secondary dark:text-text-dark-secondary mb-1">{icon}{label}</div>
      <p className="text-2xl font-bold text-text-light-primary dark:text-text-dark-primary">{value}</p>
      <div className="flex items-center gap-1 mt-1">
        {change >= 0 ? <TrendingUp className="w-3.5 h-3.5 text-success-500" /> : <TrendingDown className="w-3.5 h-3.5 text-danger-500" />}
        <span className={cn("text-xs font-medium", change >= 0 ? "text-success-600" : "text-danger-600")}>{change >= 0 ? "+" : ""}{change}%</span>
      </div>
    </div>
  );
}

import { useState, useRef } from "react";
import { useAppStore } from "@/stores/appStore";
import { useDataStore } from "@/stores/dataStore";
import { cn } from "@/utils/cn";
import { saveTextFilePortable } from "@/utils/fileSave";
import { APP_VERSION, APP_BUILD, APP_NAME } from "@/constants";
import {
  Settings as SettingsIcon, Building, Palette, Bell, Database,
  Save, Download, Upload, Trash2,
  Sun, Moon, Info, Activity, Globe, ChevronRight, Check,
  Languages, Clock, Calendar, Hash, Ruler, MapPin
} from "lucide-react";

type SettingsTab = "company" | "appearance" | "notifications" | "locale" | "currency" | "database" | "activity" | "about";

export function Settings() {
  const {
    settings, updateSettings, theme, setTheme,
    currencies, updateCurrencyRate,
    activityLog, clearActivityLog,
    addNotification, addActivityLog,
  } = useAppStore();
  const { customers, jobs, quotations, resetAllData } = useDataStore();
  const [activeTab, setActiveTab] = useState<SettingsTab>("company");
  const [companyForm, setCompanyForm] = useState({ ...settings.company });
  const [saved, setSaved] = useState(false);
  const [notifPrefs, setNotifPrefs] = useState({
    estimateCompleted: true,
    quotationStatusChange: true,
    exportCompleted: true,
    systemAlerts: true,
  });
  const [showBackupModal, setShowBackupModal] = useState(false);
  const [backupType, setBackupType] = useState<"complete" | "data">("complete");
  const [localeSaved, setLocaleSaved] = useState(false);
  const restoreInputRef = useRef<HTMLInputElement>(null);
  const [localePrefs, setLocalePrefs] = useState({
    language: "en-IN",
    timezone: Intl.DateTimeFormat().resolvedOptions().timeZone || "Asia/Kolkata",
    dateFormat: "DD/MM/YYYY",
    timeFormat: "12h" as "12h" | "24h",
    numberFormat: "en-IN",
    firstDayOfWeek: "monday" as "monday" | "sunday" | "saturday",
    fiscalYearStart: "april" as string,
    measurementUnit: "metric" as "metric" | "imperial",
    paperSize: "A4" as "A4" | "Letter" | "Legal",
  });

  const handleSaveLocale = () => {
    addNotification({ type: "success", title: "Region Settings Saved", message: "Language & region preferences have been updated.", category: "system" });
    addActivityLog({ action: "LOCALE_UPDATED", category: "settings", description: `Locale updated: ${localePrefs.language}, TZ: ${localePrefs.timezone}, Date: ${localePrefs.dateFormat}`, user: "Current User", entityType: "settings", entityId: "", level: "info" });
    setLocaleSaved(true);
    setTimeout(() => setLocaleSaved(false), 2000);
  };

  const handleSaveCompany = () => {
    updateSettings({ company: companyForm } as any);
    setSaved(true);
    setTimeout(() => setSaved(false), 2000);
    addNotification({ type: "success", title: "Settings Saved", message: "Company settings have been updated.", category: "system" });
    addActivityLog({ action: "SETTINGS_UPDATED", category: "settings", description: "Company settings updated", user: "Current User", entityType: "settings", entityId: "", level: "info" });
  };

  const handleBackup = () => {
    setShowBackupModal(true);
  };

  const executeBackup = async () => {
    try {
      const backupData: Record<string, string | null> = {};
      let keys: string[] = [];

      if (backupType === "complete") {
        keys = ["print-estimator-app", "print-estimator-data", "print-estimator-estimation"];
      } else {
        keys = ["print-estimator-data"];
      }

      keys.forEach(key => {
        const val = localStorage.getItem(key);
        if (val) backupData[key] = val;
      });

      const jsonStr = JSON.stringify(backupData, null, 2);
      const date = new Date().toISOString().split("T")[0];
      const defaultFilename = `print-estimator-${backupType}-backup-${date}.json`;

      const filePath = await saveTextFilePortable(
        {
          filters: [{ name: "JSON Backup", extensions: ["json"] }],
          defaultPath: defaultFilename,
        },
        jsonStr
      );

      if (!filePath) {
        setShowBackupModal(false);
        return; // User cancelled
      }

      addNotification({ type: "success", title: "Backup Saved", message: `Backup saved successfully.`, category: "system" });
      addActivityLog({ action: "BACKUP_CREATED", category: "settings", description: `Backup exported (${backupType}) to: ${filePath}`, user: "Current User", entityType: "settings", entityId: "", level: "info" });
      setShowBackupModal(false);
    } catch (error: any) {
      addNotification({ type: "error", title: "Backup Failed", message: error.message || "An error occurred while saving the backup.", category: "system" });
      setShowBackupModal(false);
    }
  };

  const handleRestore = async () => {
    try {
      let fileContent = "";

      try {
        const [{ open }, { readTextFile }] = await Promise.all([
          import("@tauri-apps/plugin-dialog"),
          import("@tauri-apps/plugin-fs"),
        ]);

        const selectedPath = await open({
          multiple: false,
          filters: [{
            name: "JSON Backup",
            extensions: ["json"],
          }],
        });

        if (!selectedPath) return;
        const pathStr = Array.isArray(selectedPath) ? selectedPath[0] : selectedPath;
        fileContent = await readTextFile(pathStr);
      } catch {
        const fallback = await new Promise<string | null>((resolve) => {
          const input = restoreInputRef.current;
          if (!input) {
            resolve(null);
            return;
          }

          input.onchange = async (ev) => {
            const file = (ev.target as HTMLInputElement).files?.[0];
            if (!file) {
              resolve(null);
              return;
            }
            resolve(await file.text());
            input.value = "";
          };

          input.click();
        });

        if (!fallback) return;
        fileContent = fallback;
      }

      const data = JSON.parse(fileContent);

      if (!data || typeof data !== "object") throw new Error("Invalid backup format");

      if (window.confirm("⚠️ Are you sure? This will replace current data with the backup.")) {
        Object.entries(data).forEach(([key, value]) => {
          if (typeof value === "string") {
            localStorage.setItem(key, value);
          }
        });
        addNotification({ type: "success", title: "Restore Complete", message: "Database restored from backup. Reloading...", category: "system" });
        addActivityLog({ action: "BACKUP_RESTORED", category: "settings", description: `Database restored from backup file`, user: "Current User", entityType: "settings", entityId: "", level: "warning" });
        setTimeout(() => window.location.reload(), 1500);
      }
    } catch (error: any) {
      addNotification({ type: "error", title: "Restore Failed", message: error.message || "Invalid backup file or format.", category: "system" });
    }
  };

  const handleReset = () => {
    if (window.confirm("⚠️ This will DELETE ALL DATA and reset the application. Are you absolutely sure?")) {
      const confirmText = window.prompt("Type RESET to confirm:");
      if (confirmText === "RESET") {
        resetAllData();
        localStorage.removeItem("print-estimator-app");
        localStorage.removeItem("print-estimator-data");
        localStorage.removeItem("print-estimator-estimation");
        addNotification({ type: "error", title: "Application Reset", message: "All data has been cleared. Reloading...", category: "system" });
        setTimeout(() => window.location.reload(), 1500);
      } else {
        addNotification({ type: "info", title: "Reset Cancelled", message: "Reset was not confirmed.", category: "system" });
      }
    }
  };

  const handleExportActivityLog = async () => {
    try {
      const csv = [
        "Timestamp,Action,Category,Description,User,Level",
        ...activityLog.map(l =>
          `"${new Date(l.timestamp).toISOString()}","${l.action}","${l.category}","${l.description.replace(/"/g, '""')}","${l.user}","${l.level}"`
        )
      ].join("\n");

      const filePath = await saveTextFilePortable(
        {
          filters: [{ name: "CSV Files", extensions: ["csv"] }],
          defaultPath: "activity-log.csv",
        },
        csv
      );

      if (!filePath) return;
      addNotification({ type: "success", title: "Activity Log Exported", message: `${activityLog.length} entries exported to ${filePath}.`, category: "export" });
    } catch (error: any) {
      addNotification({ type: "error", title: "Export Failed", message: error.message || "Failed to export activity log.", category: "system" });
    }
  };

  const TABS: { key: SettingsTab; label: string; icon: React.ReactNode }[] = [
    { key: "company", label: "Company", icon: <Building className="w-4 h-4" /> },
    { key: "appearance", label: "Appearance", icon: <Palette className="w-4 h-4" /> },
    { key: "locale", label: "Language & Region", icon: <Languages className="w-4 h-4" /> },
    { key: "notifications", label: "Notifications", icon: <Bell className="w-4 h-4" /> },
    { key: "currency", label: "Currency", icon: <Globe className="w-4 h-4" /> },
    { key: "database", label: "Database", icon: <Database className="w-4 h-4" /> },
    { key: "activity", label: "Activity Log", icon: <Activity className="w-4 h-4" /> },
    { key: "about", label: "About", icon: <Info className="w-4 h-4" /> },
  ];

  return (
    <div className="space-y-6 animate-in">
      <input ref={restoreInputRef} type="file" accept=".json,application/json" className="hidden" />
      <div>
        <h1 className="text-2xl font-bold text-text-light-primary dark:text-text-dark-primary flex items-center gap-2">
          <SettingsIcon className="w-6 h-6" /> Settings
        </h1>
        <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary mt-1">
          Configure application preferences, company details, and data management
        </p>
      </div>

      <div className="flex gap-6">
        {/* Settings Nav */}
        <div className="w-56 shrink-0 space-y-1">
          {TABS.map(tab => (
            <button key={tab.key} onClick={() => setActiveTab(tab.key)} className={cn("w-full flex items-center gap-2.5 px-3 py-2.5 rounded-xl text-sm transition-all text-left", activeTab === tab.key ? "bg-primary-50 dark:bg-primary-500/10 text-primary-700 dark:text-primary-400 font-semibold" : "text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-tertiary dark:hover:bg-surface-dark-tertiary")}>
              {tab.icon}
              {tab.label}
              <ChevronRight className="w-3.5 h-3.5 ml-auto opacity-40" />
            </button>
          ))}
        </div>

        {/* Content */}
        <div className="flex-1 min-w-0">
          {activeTab === "company" && (
            <div className="card p-6 space-y-5 animate-in">
              <h3 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary">Company Information</h3>
              <div className="grid grid-cols-2 gap-4">
                <div><label className="label">Company Name</label><input type="text" value={companyForm.name} onChange={e => setCompanyForm({ ...companyForm, name: e.target.value })} className="input-field" /></div>
                <div><label className="label">Website</label><input type="text" value={companyForm.website} onChange={e => setCompanyForm({ ...companyForm, website: e.target.value })} className="input-field" /></div>
                <div><label className="label">Email</label><input type="email" value={companyForm.email} onChange={e => setCompanyForm({ ...companyForm, email: e.target.value })} className="input-field" /></div>
                <div><label className="label">Phone</label><input type="tel" value={companyForm.phone} onChange={e => setCompanyForm({ ...companyForm, phone: e.target.value })} className="input-field" /></div>
                <div className="col-span-2"><label className="label">Address</label><input type="text" value={companyForm.address} onChange={e => setCompanyForm({ ...companyForm, address: e.target.value })} className="input-field" /></div>
                <div><label className="label">City</label><input type="text" value={companyForm.city} onChange={e => setCompanyForm({ ...companyForm, city: e.target.value })} className="input-field" /></div>
                <div><label className="label">State</label><input type="text" value={companyForm.state} onChange={e => setCompanyForm({ ...companyForm, state: e.target.value })} className="input-field" /></div>
                <div><label className="label">GST Number</label><input type="text" value={companyForm.gstNumber} onChange={e => setCompanyForm({ ...companyForm, gstNumber: e.target.value })} className="input-field" /></div>
                <div><label className="label">PAN Number</label><input type="text" value={companyForm.panNumber} onChange={e => setCompanyForm({ ...companyForm, panNumber: e.target.value })} className="input-field" /></div>
              </div>
              <div className="flex justify-end gap-3 pt-4 border-t border-surface-light-border dark:border-surface-dark-border">
                <button onClick={handleSaveCompany} className="btn-primary flex items-center gap-1.5">{saved ? <Check className="w-4 h-4" /> : <Save className="w-4 h-4" />}{saved ? "Saved!" : "Save Changes"}</button>
              </div>
            </div>
          )}

          {activeTab === "appearance" && (
            <div className="card p-6 space-y-6 animate-in">
              <h3 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary">Appearance</h3>
              <div>
                <label className="label mb-3">Theme</label>
                <div className="flex gap-4">
                  <button onClick={() => setTheme("light")} className={cn("flex-1 p-6 rounded-xl border-2 text-center transition-all", theme === "light" ? "border-primary-500 bg-primary-50 dark:bg-primary-500/10" : "border-surface-light-border dark:border-surface-dark-border hover:border-primary-300")}>
                    <Sun className="w-8 h-8 mx-auto mb-2 text-amber-500" />
                    <p className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary">Light</p>
                    <p className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary mt-1">Clean and bright</p>
                  </button>
                  <button onClick={() => setTheme("dark")} className={cn("flex-1 p-6 rounded-xl border-2 text-center transition-all", theme === "dark" ? "border-primary-500 bg-primary-50 dark:bg-primary-500/10" : "border-surface-light-border dark:border-surface-dark-border hover:border-primary-300")}>
                    <Moon className="w-8 h-8 mx-auto mb-2 text-blue-400" />
                    <p className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary">Dark</p>
                    <p className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary mt-1">Easy on the eyes</p>
                  </button>
                </div>
              </div>
            </div>
          )}

          {activeTab === "notifications" && (
            <div className="card p-6 space-y-4 animate-in">
              <h3 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary">Notification Preferences</h3>
              {[
                { key: "estimateCompleted" as const, label: "Estimation Completed" },
                { key: "quotationStatusChange" as const, label: "Quotation Status Changes" },
                { key: "exportCompleted" as const, label: "Export/PDF Generated" },
                { key: "systemAlerts" as const, label: "System Alerts" },
              ].map(item => (
                <label key={item.key} className="flex items-center justify-between p-3 rounded-lg bg-surface-light-secondary dark:bg-surface-dark-tertiary cursor-pointer">
                  <span className="text-sm text-text-light-primary dark:text-text-dark-primary">{item.label}</span>
                  <input
                    type="checkbox"
                    checked={notifPrefs[item.key]}
                    onChange={(e) => {
                      setNotifPrefs(prev => ({ ...prev, [item.key]: e.target.checked }));
                      addNotification({
                        type: "info",
                        title: "Notification Preference",
                        message: `${item.label}: ${e.target.checked ? "enabled" : "disabled"}`,
                        category: "system",
                      });
                    }}
                    className="w-4 h-4 rounded border-gray-300 text-primary-600 focus:ring-primary-500"
                  />
                </label>
              ))}
            </div>
          )}

          {activeTab === "locale" && (
            <div className="space-y-4 animate-in">
              {/* Language & Display */}
              <div className="card p-6 space-y-5">
                <div className="flex items-center gap-2 mb-1">
                  <Languages className="w-5 h-5 text-primary-500" />
                  <h3 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary">Language & Display</h3>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="label">Application Language</label>
                    <select value={localePrefs.language} onChange={e => setLocalePrefs(p => ({ ...p, language: e.target.value }))} className="input-field">
                      <option value="en-IN">English (India)</option>
                      <option value="en-US">English (United States)</option>
                      <option value="en-GB">English (United Kingdom)</option>
                      <option value="hi-IN">हिन्दी (Hindi)</option>
                      <option value="mr-IN">मराठी (Marathi)</option>
                      <option value="ta-IN">தமிழ் (Tamil)</option>
                      <option value="te-IN">తెలుగు (Telugu)</option>
                      <option value="gu-IN">ગુજરાતી (Gujarati)</option>
                      <option value="bn-IN">বাংলা (Bengali)</option>
                      <option value="kn-IN">ಕನ್ನಡ (Kannada)</option>
                    </select>
                  </div>
                  <div>
                    <label className="label">Number Format</label>
                    <select value={localePrefs.numberFormat} onChange={e => setLocalePrefs(p => ({ ...p, numberFormat: e.target.value }))} className="input-field">
                      <option value="en-IN">Indian (12,34,567.89)</option>
                      <option value="en-US">US/International (1,234,567.89)</option>
                      <option value="de-DE">European (1.234.567,89)</option>
                      <option value="fr-FR">French (1 234 567,89)</option>
                    </select>
                  </div>
                </div>
                {/* Live Preview */}
                <div className="p-3 rounded-xl bg-gradient-to-r from-primary-50 to-blue-50 dark:from-primary-500/5 dark:to-blue-500/5 border border-primary-200 dark:border-primary-500/20">
                  <p className="text-[10px] uppercase font-medium text-primary-600 dark:text-primary-400 mb-1.5 tracking-wider">Live Preview</p>
                  <p className="text-sm text-text-light-primary dark:text-text-dark-primary font-mono">
                    {new Intl.NumberFormat(localePrefs.numberFormat, { style: "currency", currency: "INR" }).format(1234567.89)}
                    {" · "}
                    {new Intl.NumberFormat(localePrefs.numberFormat).format(98765432.1)}
                  </p>
                </div>
              </div>

              {/* Date & Time */}
              <div className="card p-6 space-y-5">
                <div className="flex items-center gap-2 mb-1">
                  <Clock className="w-5 h-5 text-amber-500" />
                  <h3 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary">Date & Time</h3>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="label">Timezone</label>
                    <select value={localePrefs.timezone} onChange={e => setLocalePrefs(p => ({ ...p, timezone: e.target.value }))} className="input-field">
                      <option value="Asia/Kolkata">Asia/Kolkata (IST, UTC+5:30)</option>
                      <option value="America/New_York">America/New York (EST, UTC−5)</option>
                      <option value="America/Chicago">America/Chicago (CST, UTC−6)</option>
                      <option value="America/Los_Angeles">America/Los Angeles (PST, UTC−8)</option>
                      <option value="Europe/London">Europe/London (GMT, UTC+0)</option>
                      <option value="Europe/Berlin">Europe/Berlin (CET, UTC+1)</option>
                      <option value="Asia/Dubai">Asia/Dubai (GST, UTC+4)</option>
                      <option value="Asia/Singapore">Asia/Singapore (SGT, UTC+8)</option>
                      <option value="Asia/Tokyo">Asia/Tokyo (JST, UTC+9)</option>
                      <option value="Australia/Sydney">Australia/Sydney (AEST, UTC+10)</option>
                    </select>
                  </div>
                  <div>
                    <label className="label">Date Format</label>
                    <select value={localePrefs.dateFormat} onChange={e => setLocalePrefs(p => ({ ...p, dateFormat: e.target.value }))} className="input-field">
                      <option value="DD/MM/YYYY">DD/MM/YYYY (28/02/2026)</option>
                      <option value="MM/DD/YYYY">MM/DD/YYYY (02/28/2026)</option>
                      <option value="YYYY-MM-DD">YYYY-MM-DD (2026-02-28)</option>
                      <option value="DD-MMM-YYYY">DD-MMM-YYYY (28-Feb-2026)</option>
                      <option value="MMM DD, YYYY">MMM DD, YYYY (Feb 28, 2026)</option>
                      <option value="DD.MM.YYYY">DD.MM.YYYY (28.02.2026)</option>
                    </select>
                  </div>
                  <div>
                    <label className="label">Time Format</label>
                    <div className="flex gap-3">
                      <button onClick={() => setLocalePrefs(p => ({ ...p, timeFormat: "12h" }))} className={cn("flex-1 py-2.5 rounded-xl border-2 text-sm font-medium transition-all", localePrefs.timeFormat === "12h" ? "border-primary-500 bg-primary-50 dark:bg-primary-500/10 text-primary-700 dark:text-primary-400" : "border-surface-light-border dark:border-surface-dark-border text-text-light-secondary dark:text-text-dark-secondary hover:border-primary-300")}>
                        12-Hour
                      </button>
                      <button onClick={() => setLocalePrefs(p => ({ ...p, timeFormat: "24h" }))} className={cn("flex-1 py-2.5 rounded-xl border-2 text-sm font-medium transition-all", localePrefs.timeFormat === "24h" ? "border-primary-500 bg-primary-50 dark:bg-primary-500/10 text-primary-700 dark:text-primary-400" : "border-surface-light-border dark:border-surface-dark-border text-text-light-secondary dark:text-text-dark-secondary hover:border-primary-300")}>
                        24-Hour
                      </button>
                    </div>
                  </div>
                  <div>
                    <label className="label">First Day of Week</label>
                    <select value={localePrefs.firstDayOfWeek} onChange={e => setLocalePrefs(p => ({ ...p, firstDayOfWeek: e.target.value as any }))} className="input-field">
                      <option value="monday">Monday</option>
                      <option value="sunday">Sunday</option>
                      <option value="saturday">Saturday</option>
                    </select>
                  </div>
                </div>
                {/* Live Preview */}
                <div className="p-3 rounded-xl bg-gradient-to-r from-amber-50 to-orange-50 dark:from-amber-500/5 dark:to-orange-500/5 border border-amber-200 dark:border-amber-500/20">
                  <p className="text-[10px] uppercase font-medium text-amber-600 dark:text-amber-400 mb-1.5 tracking-wider">Live Preview</p>
                  <p className="text-sm text-text-light-primary dark:text-text-dark-primary font-mono">
                    {new Date().toLocaleDateString(localePrefs.language, { year: "numeric", month: "2-digit", day: "2-digit", timeZone: localePrefs.timezone })}
                    {" · "}
                    {new Date().toLocaleTimeString(localePrefs.language, { hour: "2-digit", minute: "2-digit", second: "2-digit", hour12: localePrefs.timeFormat === "12h", timeZone: localePrefs.timezone })}
                  </p>
                </div>
              </div>

              {/* Business & Measurement */}
              <div className="card p-6 space-y-5">
                <div className="flex items-center gap-2 mb-1">
                  <Ruler className="w-5 h-5 text-emerald-500" />
                  <h3 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary">Business & Measurement</h3>
                </div>
                <div className="grid grid-cols-3 gap-4">
                  <div>
                    <label className="label">Fiscal Year Start</label>
                    <select value={localePrefs.fiscalYearStart} onChange={e => setLocalePrefs(p => ({ ...p, fiscalYearStart: e.target.value }))} className="input-field">
                      <option value="january">January</option>
                      <option value="april">April (India Standard)</option>
                      <option value="july">July</option>
                      <option value="october">October</option>
                    </select>
                  </div>
                  <div>
                    <label className="label">Measurement Units</label>
                    <select value={localePrefs.measurementUnit} onChange={e => setLocalePrefs(p => ({ ...p, measurementUnit: e.target.value as any }))} className="input-field">
                      <option value="metric">Metric (mm, cm, kg)</option>
                      <option value="imperial">Imperial (in, ft, lbs)</option>
                    </select>
                  </div>
                  <div>
                    <label className="label">Default Paper Size</label>
                    <select value={localePrefs.paperSize} onChange={e => setLocalePrefs(p => ({ ...p, paperSize: e.target.value as any }))} className="input-field">
                      <option value="A4">A4 (210 × 297 mm)</option>
                      <option value="Letter">Letter (8.5 × 11 in)</option>
                      <option value="Legal">Legal (8.5 × 14 in)</option>
                    </select>
                  </div>
                </div>
              </div>

              {/* Save Button */}
              <div className="flex justify-end pt-2">
                <button onClick={handleSaveLocale} className="btn-primary flex items-center gap-1.5">
                  {localeSaved ? <Check className="w-4 h-4" /> : <Save className="w-4 h-4" />}
                  {localeSaved ? "Saved!" : "Save Preferences"}
                </button>
              </div>
            </div>
          )}

          {activeTab === "currency" && (
            <div className="card p-6 space-y-4 animate-in">
              <h3 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary">Currency Exchange Rates</h3>
              <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">All rates relative to 1 unit = ₹X (Indian Rupees)</p>
              <div className="space-y-2">
                {currencies.map(c => (
                  <div key={c.code} className="flex items-center gap-4 p-3 bg-surface-light-secondary dark:bg-surface-dark-tertiary rounded-lg">
                    <span className="text-lg font-bold w-10">{c.symbol}</span>
                    <div className="flex-1">
                      <p className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary">{c.code} — {c.name}</p>
                    </div>
                    <div className="flex items-center gap-2">
                      <span className="text-xs text-text-light-tertiary">1 {c.code} =</span>
                      <input type="number" value={c.exchangeRate} onChange={e => updateCurrencyRate(c.code, parseFloat(e.target.value) || 0)} className="input-field w-24 text-right text-sm py-1" step="0.01" disabled={c.code === "INR"} />
                      <span className="text-xs text-text-light-tertiary">₹</span>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeTab === "database" && (
            <div className="space-y-4 animate-in">
              {/* Data Summary */}
              <div className="card p-6 space-y-4">
                <h3 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary">Data Summary</h3>
                <div className="grid grid-cols-3 gap-4">
                  <div className="p-4 rounded-xl bg-surface-light-secondary dark:bg-surface-dark-tertiary text-center">
                    <p className="text-2xl font-bold text-text-light-primary dark:text-text-dark-primary">{customers.length}</p>
                    <p className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary mt-1">Customers</p>
                  </div>
                  <div className="p-4 rounded-xl bg-surface-light-secondary dark:bg-surface-dark-tertiary text-center">
                    <p className="text-2xl font-bold text-text-light-primary dark:text-text-dark-primary">{jobs.length}</p>
                    <p className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary mt-1">Jobs</p>
                  </div>
                  <div className="p-4 rounded-xl bg-surface-light-secondary dark:bg-surface-dark-tertiary text-center">
                    <p className="text-2xl font-bold text-text-light-primary dark:text-text-dark-primary">{quotations.length}</p>
                    <p className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary mt-1">Quotations</p>
                  </div>
                </div>
              </div>

              <div className="card p-6 space-y-4">
                <h3 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary">Data Management</h3>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  <button onClick={handleBackup} className="p-4 rounded-xl border-2 border-surface-light-border dark:border-surface-dark-border hover:border-primary-500 transition-all text-center">
                    <Download className="w-8 h-8 mx-auto mb-2 text-blue-500" />
                    <p className="text-sm font-semibold">Backup Data</p>
                    <p className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary mt-1">Export all data as JSON</p>
                  </button>
                  <button onClick={handleRestore} className="p-4 rounded-xl border-2 border-surface-light-border dark:border-surface-dark-border hover:border-amber-500 transition-all text-center">
                    <Upload className="w-8 h-8 mx-auto mb-2 text-amber-500" />
                    <p className="text-sm font-semibold">Restore Data</p>
                    <p className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary mt-1">Import from backup JSON</p>
                  </button>
                  <button onClick={handleReset} className="p-4 rounded-xl border-2 border-danger-300 dark:border-danger-500/30 hover:border-danger-500 transition-all text-center">
                    <Trash2 className="w-8 h-8 mx-auto mb-2 text-danger-500" />
                    <p className="text-sm font-semibold text-danger-600">Reset Application</p>
                    <p className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary mt-1">Delete all data</p>
                  </button>
                </div>
              </div>
            </div>
          )}

          {activeTab === "activity" && (
            <div className="card p-6 space-y-4 animate-in">
              <div className="flex items-center justify-between">
                <h3 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary">Activity Log</h3>
                <div className="flex gap-2">
                  <button onClick={clearActivityLog} className="btn-ghost text-xs text-danger-500">Clear Log</button>
                  <button onClick={handleExportActivityLog} className="btn-secondary text-xs flex items-center gap-1"><Download className="w-3.5 h-3.5" /> Export</button>
                </div>
              </div>
              {activityLog.length === 0 ? (
                <div className="text-center py-12 text-text-light-tertiary dark:text-text-dark-tertiary">
                  <Activity className="w-12 h-12 mx-auto mb-3 opacity-40" />
                  <p>No activity recorded yet</p>
                </div>
              ) : (
                <div className="space-y-2 max-h-[500px] overflow-y-auto">
                  {activityLog.slice(0, 50).map(log => (
                    <div key={log.id} className="flex items-start gap-3 p-3 bg-surface-light-secondary dark:bg-surface-dark-tertiary rounded-lg text-sm">
                      <div className={cn("w-2 h-2 rounded-full mt-1.5 shrink-0", log.level === "error" ? "bg-danger-500" : log.level === "warning" ? "bg-warning-500" : "bg-success-500")} />
                      <div className="flex-1 min-w-0">
                        <p className="text-text-light-primary dark:text-text-dark-primary font-medium">{log.action}</p>
                        <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-0.5">{log.description}</p>
                      </div>
                      <span className="text-[10px] text-text-light-tertiary dark:text-text-dark-tertiary shrink-0">{new Date(log.timestamp).toLocaleTimeString()}</span>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          {activeTab === "about" && (
            <div className="card p-6 space-y-6 animate-in">
              <div className="text-center py-6">
                <div className="w-16 h-16 rounded-2xl bg-gradient-to-br from-primary-500 to-primary-700 flex items-center justify-center mx-auto mb-4 shadow-lg">
                  <SettingsIcon className="w-8 h-8 text-white" />
                </div>
                <h2 className="text-2xl font-bold text-text-light-primary dark:text-text-dark-primary">{APP_NAME}</h2>
                <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary mt-1">Nuclear-Grade Commercial Print Estimation Platform</p>
              </div>
              <div className="grid grid-cols-2 gap-4 max-w-md mx-auto">
                <DetailItem label="Version" value={APP_VERSION} />
                <DetailItem label="Build" value={APP_BUILD} />
                <DetailItem label="Platform" value="Windows (Tauri 2)" />
                <DetailItem label="Stack" value="Rust + React + TypeScript" />
                <DetailItem label="Database" value="SQLite (WAL)" />
                <DetailItem label="License" value="Proprietary" />
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Backup Modal */}
      {showBackupModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-surface-light-primary dark:bg-surface-dark-primary rounded-2xl shadow-2xl w-full max-w-md overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="p-6">
              <h2 className="text-xl font-bold text-text-light-primary dark:text-text-dark-primary mb-2">Backup Data</h2>
              <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary mb-6">Choose what data you would like to include in this backup.</p>

              <div className="space-y-3">
                <label className={cn("flex items-start gap-4 p-4 rounded-xl border-2 cursor-pointer transition-all", backupType === "complete" ? "border-primary-500 bg-primary-50 dark:bg-primary-500/10" : "border-surface-light-border dark:border-surface-dark-border hover:border-primary-300")}>
                  <input type="radio" name="backupType" value="complete" checked={backupType === "complete"} onChange={() => setBackupType("complete")} className="mt-1 w-4 h-4 text-primary-600 border-gray-300 focus:ring-primary-500" />
                  <div>
                    <p className="font-semibold text-text-light-primary dark:text-text-dark-primary">Complete Application</p>
                    <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">Includes all application settings, templates, estimation configurations, customers, jobs, and quotations.</p>
                  </div>
                </label>

                <label className={cn("flex items-start gap-4 p-4 rounded-xl border-2 cursor-pointer transition-all", backupType === "data" ? "border-primary-500 bg-primary-50 dark:bg-primary-500/10" : "border-surface-light-border dark:border-surface-dark-border hover:border-primary-300")}>
                  <input type="radio" name="backupType" value="data" checked={backupType === "data"} onChange={() => setBackupType("data")} className="mt-1 w-4 h-4 text-primary-600 border-gray-300 focus:ring-primary-500" />
                  <div>
                    <p className="font-semibold text-text-light-primary dark:text-text-dark-primary">Data Only</p>
                    <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">Includes only customers, jobs, and quotations data. Settings and configurations are ignored.</p>
                  </div>
                </label>
              </div>

              <div className="flex gap-3 justify-end mt-8">
                <button onClick={() => setShowBackupModal(false)} className="btn-ghost">Cancel</button>
                <button onClick={executeBackup} className="btn-primary flex items-center gap-2">
                  <Download className="w-4 h-4" /> Save Backup
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

function DetailItem({ label, value }: { label: string; value: string }) {
  return (
    <div className="p-3 bg-surface-light-secondary dark:bg-surface-dark-tertiary rounded-lg">
      <p className="text-[10px] text-text-light-tertiary dark:text-text-dark-tertiary uppercase font-medium">{label}</p>
      <p className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary mt-0.5">{value}</p>
    </div>
  );
}

import { useMemo } from "react";
import { useInventoryStore } from "@/stores/inventoryStore";
import { useMachineStore } from "@/stores/machineStore";
import { useAppStore } from "@/stores/appStore";
import { formatCurrency, formatNumber } from "@/utils/format";
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell } from "recharts";
import { TrendingUp, Package, AlertTriangle, ArrowRightLeft } from "lucide-react";

const CAT_COLORS: Record<string, string> = {
    paper: "#3b82f6", plates: "#8b5cf6", finishing: "#22c55e", packing: "#f59e0b",
    ink: "#ef4444", chemicals: "#06b6d4", consumables: "#ec4899", spare_parts: "#f97316", other: "#64748b",
};

export function AnalyticsTab() {
    const { theme } = useAppStore();
    const { items, nmiRecords, transfers } = useInventoryStore();
    const { machines } = useMachineStore();

    const totalValue = items.reduce((s, i) => s + i.stock * i.costPerUnit, 0);
    const lowStock = items.filter(i => i.stock <= i.minLevel && i.status === "active");
    const totalTransferCost = transfers.reduce((s, t) => s + t.totalTransferCost, 0);

    const categoryValues = useMemo(() => {
        const map: Record<string, number> = {};
        items.forEach(i => { map[i.category] = (map[i.category] || 0) + i.stock * i.costPerUnit; });
        return Object.entries(map).map(([cat, val]) => ({
            category: cat.charAt(0).toUpperCase() + cat.slice(1).replace("_", " "),
            value: val, fill: CAT_COLORS[cat] || "#64748b",
        }));
    }, [items]);

    const categoryStockData = useMemo(() => {
        const map: Record<string, { count: number; stock: number }> = {};
        items.forEach(i => {
            if (!map[i.category]) map[i.category] = { count: 0, stock: 0 };
            map[i.category].count++; map[i.category].stock += i.stock;
        });
        return Object.entries(map).map(([cat, d]) => ({
            name: cat.charAt(0).toUpperCase() + cat.slice(1).replace("_", " "),
            items: d.count, stock: d.stock, fill: CAT_COLORS[cat] || "#64748b",
        }));
    }, [items]);

    const movementClassData = useMemo(() => {
        const map: Record<string, number> = {};
        items.forEach(i => { map[i.movementClass] = (map[i.movementClass] || 0) + 1; });
        return Object.entries(map).map(([cls, count]) => ({
            name: cls.replace("_", " "), value: count,
            fill: cls === "fast_moving" ? "#22c55e" : cls === "slow_moving" ? "#f59e0b" : "#ef4444",
        }));
    }, [items]);

    const warehouseData = useMemo(() => {
        const map: Record<string, { items: number; value: number }> = {};
        items.forEach(i => {
            if (!map[i.warehouse]) map[i.warehouse] = { items: 0, value: 0 };
            map[i.warehouse].items++; map[i.warehouse].value += i.stock * i.costPerUnit;
        });
        return Object.entries(map).map(([wh, d]) => ({ warehouse: wh, ...d }));
    }, [items]);

    const machineStatusData = useMemo(() => {
        const map: Record<string, number> = {};
        Array.from(machines.values()).forEach(m => { map[m.status] = (map[m.status] || 0) + 1; });
        return Object.entries(map).map(([status, count]) => ({
            name: status, value: count,
            fill: status === "running" ? "#22c55e" : status === "idle" ? "#3b82f6" : status === "maintenance" ? "#f59e0b" : "#64748b",
        }));
    }, [machines]);

    return (
        <div className="space-y-4">
            {/* Top Summary Cards */}
            <div className="grid grid-cols-5 gap-3">
                {[
                    { label: "Total Inventory Value", value: formatCurrency(totalValue), icon: <TrendingUp className="w-5 h-5" />, color: "text-primary-600 dark:text-primary-400", bg: "bg-primary-50 dark:bg-primary-500/10" },
                    { label: "Total Items", value: items.length, icon: <Package className="w-5 h-5" />, color: "text-blue-600 dark:text-blue-400", bg: "bg-blue-50 dark:bg-blue-500/10" },
                    { label: "Low Stock Items", value: lowStock.length, icon: <AlertTriangle className="w-5 h-5" />, color: "text-danger-600 dark:text-danger-400", bg: "bg-danger-50 dark:bg-danger-500/10" },
                    { label: "Active Machines", value: Array.from(machines.values()).filter(m => m.status === "ACTIVE").length, icon: <Package className="w-5 h-5" />, color: "text-success-600 dark:text-success-400", bg: "bg-success-50 dark:bg-success-500/10" },
                    { label: "Transfer Costs", value: formatCurrency(totalTransferCost), icon: <ArrowRightLeft className="w-5 h-5" />, color: "text-purple-600 dark:text-purple-400", bg: "bg-purple-50 dark:bg-purple-500/10" },
                ].map(c => (
                    <div key={c.label} className="card p-3">
                        <div className="flex items-center gap-2 mb-2">
                            <div className={`p-1.5 rounded-lg ${c.bg}`}>{c.icon}</div>
                            <p className="text-[10px] uppercase font-semibold text-text-light-tertiary dark:text-text-dark-tertiary tracking-wider">{c.label}</p>
                        </div>
                        <p className={`text-xl font-bold ${c.color}`}>{c.value}</p>
                    </div>
                ))}
            </div>

            <div className="grid grid-cols-2 gap-4">
                {/* Value by Category */}
                <div className="card p-4">
                    <h3 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary mb-3">Value by Category</h3>
                    <div className="h-56">
                        <ResponsiveContainer width="100%" height="100%" minWidth={0} minHeight={1}>
                            <BarChart data={categoryValues} layout="vertical">
                                <CartesianGrid strokeDasharray="3 3" stroke={theme === "dark" ? "#334155" : "#e2e8f0"} />
                                <XAxis type="number" tick={{ fontSize: 10, fill: theme === "dark" ? "#94a3b8" : "#64748b" }} tickFormatter={v => `₹${(v / 100000).toFixed(0)}L`} />
                                <YAxis type="category" dataKey="category" tick={{ fontSize: 11, fill: theme === "dark" ? "#94a3b8" : "#64748b" }} width={80} />
                                <Tooltip contentStyle={{ backgroundColor: theme === "dark" ? "#1e293b" : "#fff", borderRadius: "8px", fontSize: "12px", border: `1px solid ${theme === "dark" ? "#475569" : "#e2e8f0"}` }} formatter={(v: any) => [formatCurrency(v as number), "Value"]} />
                                <Bar dataKey="value" radius={[0, 4, 4, 0]} fill="#3b82f6" />
                            </BarChart>
                        </ResponsiveContainer>
                    </div>
                </div>

                {/* Movement Classification */}
                <div className="card p-4">
                    <h3 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary mb-3">Movement Classification</h3>
                    <div className="h-56 flex items-center justify-center">
                        <ResponsiveContainer width="100%" height="100%" minWidth={0} minHeight={1}>
                            <PieChart>
                                <Pie data={movementClassData} cx="50%" cy="50%" innerRadius={50} outerRadius={80} paddingAngle={5} dataKey="value" label={({ name, value }) => `${name}: ${value}`}>
                                    {movementClassData.map((entry, idx) => <Cell key={idx} fill={entry.fill} />)}
                                </Pie>
                                <Tooltip />
                            </PieChart>
                        </ResponsiveContainer>
                    </div>
                </div>

                {/* Stock by Category */}
                <div className="card p-4">
                    <h3 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary mb-3">Items per Category</h3>
                    <div className="h-52">
                        <ResponsiveContainer width="100%" height="100%" minWidth={0} minHeight={1}>
                            <BarChart data={categoryStockData}>
                                <CartesianGrid strokeDasharray="3 3" stroke={theme === "dark" ? "#334155" : "#e2e8f0"} />
                                <XAxis dataKey="name" tick={{ fontSize: 10 }} />
                                <YAxis tick={{ fontSize: 10 }} />
                                <Tooltip contentStyle={{ backgroundColor: theme === "dark" ? "#1e293b" : "#fff", borderRadius: "8px", fontSize: "12px" }} />
                                <Bar dataKey="items" fill="#8b5cf6" radius={[4, 4, 0, 0]} />
                            </BarChart>
                        </ResponsiveContainer>
                    </div>
                </div>

                {/* Machine Status */}
                <div className="card p-4">
                    <h3 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary mb-3">Machine Status Distribution</h3>
                    <div className="h-52 flex items-center justify-center">
                        {machines.size > 0 ? (
                            <ResponsiveContainer width="100%" height="100%" minWidth={0} minHeight={1}>
                                <PieChart>
                                    <Pie data={machineStatusData} cx="50%" cy="50%" innerRadius={45} outerRadius={75} paddingAngle={5} dataKey="value" label={({ name, value }) => `${name}: ${value}`}>
                                        {machineStatusData.map((entry, idx) => <Cell key={idx} fill={entry.fill} />)}
                                    </Pie>
                                    <Tooltip />
                                </PieChart>
                            </ResponsiveContainer>
                        ) : <p className="text-sm text-text-light-tertiary">No machines configured</p>}
                    </div>
                </div>
            </div>

            {/* Warehouse Distribution */}
            <div className="card p-4">
                <h3 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary mb-3">Warehouse Distribution</h3>
                <div className="grid grid-cols-3 gap-3">
                    {warehouseData.map(wh => (
                        <div key={wh.warehouse} className="bg-surface-light-tertiary dark:bg-surface-dark-tertiary rounded-lg p-3 text-center">
                            <p className="text-xs font-semibold text-text-light-primary dark:text-text-dark-primary">{wh.warehouse}</p>
                            <p className="text-lg font-bold text-primary-600 dark:text-primary-400 mt-1">{wh.items} items</p>
                            <p className="text-[11px] text-text-light-tertiary">{formatCurrency(wh.value)}</p>
                        </div>
                    ))}
                </div>
            </div>
        </div>
    );
}

import { useState, useMemo } from "react";
import { useInventoryStore } from "@/stores/inventoryStore";
import { useAppStore } from "@/stores/appStore";
import { cn } from "@/utils/cn";
import { formatCurrency, formatNumber, generateId } from "@/utils/format";
import type { InventoryItem, InventoryCategory } from "@/types";
import {
    Search, Plus, Edit3, Trash2, Copy, Save, AlertTriangle,
    ChevronDown, ChevronUp, MapPin, Package, X, Filter
} from "lucide-react";

const CATEGORIES: InventoryCategory[] = ["paper", "plates", "finishing", "packing", "ink", "chemicals", "consumables", "spare_parts", "other"];
const CAT_COLORS: Record<string, string> = {
    paper: "#3b82f6", plates: "#8b5cf6", finishing: "#22c55e", packing: "#f59e0b",
    ink: "#ef4444", chemicals: "#06b6d4", consumables: "#ec4899", spare_parts: "#f97316", other: "#64748b",
};

function emptyItem(): Partial<InventoryItem> {
    return {
        name: "", sku: "", barcode: "", category: "paper" as InventoryCategory, subcategory: "", description: "", tags: [],
        stock: 0, minLevel: 0, maxLevel: 9999, reorderQty: 0, unit: "Reams", batchNumber: "", lotNumber: "",
        costPerUnit: 0, sellingPrice: 0, lastPurchasePrice: 0, avgCost: 0, taxRate: 18, hsnCode: "",
        warehouse: "Main Warehouse", zone: "A", rack: "", shelf: "", bin: "",
        supplier: "", supplierCode: "", leadTimeDays: 7, alternateSuppliers: [],
        expiryDate: "", manufacturedDate: "", lastAuditDate: "",
        weight: 0, weightUnit: "kg", length: 0, width: 0, height: 0, dimensionUnit: "mm", volumeCBM: 0,
        status: "active", condition: "new", nmiFlag: false, movementClass: "fast_moving",
        qualityGrade: "A", certifications: [], shelfLifeDays: 0, storageConditions: "", handlingInstructions: "", notes: "",
    };
}

export function InventoryItemsTab() {
    const { items, addItem, updateItem, deleteItem, duplicateItem } = useInventoryStore();
    const { addNotification, addActivityLog } = useAppStore();
    const [search, setSearch] = useState("");
    const [catFilter, setCatFilter] = useState<string>("all");
    const [statusFilter, setStatusFilter] = useState<string>("all");
    const [showModal, setShowModal] = useState(false);
    const [editId, setEditId] = useState<string | null>(null);
    const [deleteConfirm, setDeleteConfirm] = useState<string | null>(null);
    const [form, setForm] = useState<Partial<InventoryItem>>(emptyItem());
    const [page, setPage] = useState(1);
    const perPage = 10;

    const filtered = useMemo(() => {
        let r = [...items];
        if (search) { const q = search.toLowerCase(); r = r.filter(i => i.name.toLowerCase().includes(q) || i.sku.toLowerCase().includes(q) || i.supplier.toLowerCase().includes(q)); }
        if (catFilter !== "all") r = r.filter(i => i.category === catFilter);
        if (statusFilter !== "all") r = r.filter(i => i.status === statusFilter);
        return r;
    }, [items, search, catFilter, statusFilter]);

    const totalPages = Math.max(1, Math.ceil(filtered.length / perPage));
    const paginated = filtered.slice((page - 1) * perPage, page * perPage);

    const openAdd = () => { setForm(emptyItem()); setEditId(null); setShowModal(true); };
    const openEdit = (item: InventoryItem) => { setForm({ ...item }); setEditId(item.id); setShowModal(true); };

    const handleSave = () => {
        if (!form.name?.trim()) return;
        if (editId) {
            updateItem(editId, form);
            addNotification({ type: "success", title: "Item Updated", message: `${form.name} updated.`, category: "system" });
            addActivityLog({ action: "INVENTORY_UPDATED", category: "inventory", description: `Updated: ${form.name}`, user: "Current User", entityType: "inventory", entityId: editId, level: "info" });
        } else {
            addItem(form as Omit<InventoryItem, "id" | "lastUpdated">);
            addNotification({ type: "success", title: "Item Added", message: `${form.name} added to inventory.`, category: "system" });
            addActivityLog({ action: "INVENTORY_ADDED", category: "inventory", description: `Added: ${form.name}`, user: "Current User", entityType: "inventory", entityId: "", level: "info" });
        }
        setShowModal(false); setEditId(null);
    };

    const handleSaveDraft = () => {
        if (!form.name?.trim()) return;
        if (editId) { updateItem(editId, { ...form, status: "draft" }); }
        else { addItem({ ...form, status: "draft" } as Omit<InventoryItem, "id" | "lastUpdated">); }
        addNotification({ type: "info", title: "Draft Saved", message: `${form.name} saved as draft.`, category: "system" });
        setShowModal(false); setEditId(null);
    };

    const handleDelete = (id: string) => {
        const item = items.find(i => i.id === id);
        deleteItem(id);
        addNotification({ type: "warning", title: "Item Deleted", message: `${item?.name} removed.`, category: "system" });
        addActivityLog({ action: "INVENTORY_DELETED", category: "inventory", description: `Deleted: ${item?.name}`, user: "Current User", entityType: "inventory", entityId: id, level: "warning" });
        setDeleteConfirm(null);
    };

    const handleDuplicate = (id: string) => {
        duplicateItem(id);
        const item = items.find(i => i.id === id);
        addNotification({ type: "info", title: "Item Duplicated", message: `${item?.name} duplicated.`, category: "system" });
    };

    const lowStock = items.filter(i => i.stock <= i.minLevel && i.status === "active");

    return (
        <div className="space-y-4">
            {/* Low Stock Alert */}
            {lowStock.length > 0 && (
                <div className="card p-3 border-warning-500/30 bg-warning-50 dark:bg-warning-500/10">
                    <div className="flex items-center gap-2 mb-2"><AlertTriangle className="w-4 h-4 text-warning-600 dark:text-warning-400" /><span className="text-sm font-semibold text-warning-700 dark:text-warning-400">Low Stock Alert — {lowStock.length} items</span></div>
                    <div className="flex flex-wrap gap-1.5">{lowStock.map(i => (<span key={i.id} className="text-[10px] px-2 py-0.5 bg-warning-100 dark:bg-warning-500/20 text-warning-700 dark:text-warning-300 rounded-full">{i.name}: {i.stock} {i.unit}</span>))}</div>
                </div>
            )}

            {/* Toolbar */}
            <div className="flex items-center gap-3 flex-wrap">
                <div className="relative flex-1 min-w-[200px] max-w-sm">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-text-light-tertiary" />
                    <input type="text" value={search} onChange={e => setSearch(e.target.value)} placeholder="Search items..." className="input-field pl-9 text-sm" />
                </div>
                <div className="flex items-center gap-1.5 p-1 bg-surface-light-tertiary dark:bg-surface-dark-tertiary rounded-lg overflow-x-auto">
                    {["all", ...CATEGORIES].map(c => (
                        <button key={c} onClick={() => { setCatFilter(c); setPage(1); }} className={cn("px-2.5 py-1.5 rounded-md text-[11px] font-medium transition-all capitalize whitespace-nowrap", catFilter === c ? "bg-white dark:bg-surface-dark-secondary shadow-sm text-text-light-primary dark:text-text-dark-primary" : "text-text-light-secondary dark:text-text-dark-secondary")}>{c.replace("_", " ")}</button>
                    ))}
                </div>
                <select value={statusFilter} onChange={e => { setStatusFilter(e.target.value); setPage(1); }} className="input-field text-xs w-28">
                    <option value="all">All Status</option>
                    <option value="active">Active</option>
                    <option value="draft">Draft</option>
                    <option value="inactive">Inactive</option>
                    <option value="discontinued">Discontinued</option>
                </select>
                <button onClick={openAdd} className="btn-primary text-sm flex items-center gap-1.5"><Plus className="w-4 h-4" /> Add Item</button>
            </div>

            {/* Table */}
            <div className="card overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="w-full text-sm">
                        <thead>
                            <tr className="bg-surface-light-tertiary dark:bg-surface-dark-tertiary border-b border-surface-light-border dark:border-surface-dark-border">
                                <th className="py-2.5 px-3 text-left font-semibold text-xs">Item</th>
                                <th className="py-2.5 px-3 text-center font-semibold text-xs">Stock</th>
                                <th className="py-2.5 px-3 text-right font-semibold text-xs">Cost/Unit</th>
                                <th className="py-2.5 px-3 text-right font-semibold text-xs">Value</th>
                                <th className="py-2.5 px-3 text-left font-semibold text-xs">Location</th>
                                <th className="py-2.5 px-3 text-left font-semibold text-xs">Supplier</th>
                                <th className="py-2.5 px-3 text-center font-semibold text-xs">Status</th>
                                <th className="py-2.5 px-3 text-center font-semibold text-xs">Actions</th>
                            </tr>
                        </thead>
                        <tbody>
                            {paginated.map(item => (
                                <tr key={item.id} className="border-b border-surface-light-border/50 dark:border-surface-dark-border/50 hover:bg-surface-light-secondary dark:hover:bg-surface-dark-tertiary transition-colors">
                                    <td className="py-2.5 px-3">
                                        <div className="flex items-center gap-2.5">
                                            <div className="w-1.5 h-8 rounded-full" style={{ backgroundColor: CAT_COLORS[item.category] }} />
                                            <div>
                                                <p className="font-medium text-text-light-primary dark:text-text-dark-primary text-xs">{item.name}</p>
                                                <p className="text-[10px] text-text-light-tertiary dark:text-text-dark-tertiary font-mono">{item.sku}</p>
                                            </div>
                                        </div>
                                    </td>
                                    <td className="py-2.5 px-3 text-center">
                                        <div className="flex items-center justify-center gap-1">
                                            {item.stock <= item.minLevel && <AlertTriangle className="w-3 h-3 text-danger-500" />}
                                            <span className={cn("font-semibold text-xs", item.stock <= item.minLevel ? "text-danger-600 dark:text-danger-400" : "")}>{formatNumber(item.stock)}</span>
                                            <span className="text-[9px] text-text-light-tertiary">{item.unit}</span>
                                        </div>
                                        <p className="text-[9px] text-text-light-tertiary">Min: {item.minLevel} | Max: {item.maxLevel}</p>
                                    </td>
                                    <td className="py-2.5 px-3 text-right text-xs">{formatCurrency(item.costPerUnit)}</td>
                                    <td className="py-2.5 px-3 text-right font-semibold text-xs text-primary-600 dark:text-primary-400">{formatCurrency(item.stock * item.costPerUnit)}</td>
                                    <td className="py-2.5 px-3">
                                        <div className="flex items-center gap-1 text-[10px] text-text-light-secondary dark:text-text-dark-secondary">
                                            <MapPin className="w-3 h-3" />
                                            <span>{item.warehouse} / {item.zone}{item.rack ? `-${item.rack}` : ""}</span>
                                        </div>
                                    </td>
                                    <td className="py-2.5 px-3 text-xs text-text-light-secondary dark:text-text-dark-secondary">{item.supplier}</td>
                                    <td className="py-2.5 px-3 text-center">
                                        <span className={cn("text-[10px] px-2 py-0.5 rounded-full font-medium capitalize",
                                            item.status === "active" ? "bg-success-100 dark:bg-success-500/20 text-success-700 dark:text-success-400"
                                                : item.status === "draft" ? "bg-blue-100 dark:bg-blue-500/20 text-blue-700 dark:text-blue-400"
                                                    : "bg-gray-100 dark:bg-gray-500/20 text-gray-700 dark:text-gray-400"
                                        )}>{item.status}</span>
                                    </td>
                                    <td className="py-2.5 px-3 text-center">
                                        <div className="flex items-center justify-center gap-0.5">
                                            <button onClick={() => openEdit(item)} className="p-1.5 rounded-lg hover:bg-surface-light-tertiary dark:hover:bg-surface-dark-tertiary" title="Edit"><Edit3 className="w-3.5 h-3.5 text-text-light-tertiary" /></button>
                                            <button onClick={() => handleDuplicate(item.id)} className="p-1.5 rounded-lg hover:bg-surface-light-tertiary dark:hover:bg-surface-dark-tertiary" title="Duplicate"><Copy className="w-3.5 h-3.5 text-text-light-tertiary" /></button>
                                            <button onClick={() => setDeleteConfirm(item.id)} className="p-1.5 rounded-lg hover:bg-danger-50 dark:hover:bg-danger-500/10" title="Delete"><Trash2 className="w-3.5 h-3.5 text-danger-400" /></button>
                                        </div>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
                {/* Pagination */}
                <div className="flex items-center justify-between p-3 border-t border-surface-light-border dark:border-surface-dark-border text-xs text-text-light-tertiary">
                    <span>Showing {(page - 1) * perPage + 1}–{Math.min(page * perPage, filtered.length)} of {filtered.length}</span>
                    <div className="flex items-center gap-1">
                        <button disabled={page <= 1} onClick={() => setPage(p => p - 1)} className="px-2 py-1 rounded bg-surface-light-tertiary dark:bg-surface-dark-tertiary disabled:opacity-40">Prev</button>
                        {Array.from({ length: Math.min(totalPages, 5) }, (_, i) => i + 1).map(p => (
                            <button key={p} onClick={() => setPage(p)} className={cn("px-2 py-1 rounded", page === p ? "bg-primary-600 text-white" : "bg-surface-light-tertiary dark:bg-surface-dark-tertiary")}>{p}</button>
                        ))}
                        <button disabled={page >= totalPages} onClick={() => setPage(p => p + 1)} className="px-2 py-1 rounded bg-surface-light-tertiary dark:bg-surface-dark-tertiary disabled:opacity-40">Next</button>
                    </div>
                </div>
            </div>

            {/* Add/Edit Modal */}
            {showModal && <ItemFormModal form={form} setForm={setForm} onSave={handleSave} onSaveDraft={handleSaveDraft} onClose={() => { setShowModal(false); setEditId(null); }} isEdit={!!editId} />}

            {/* Delete Confirm */}
            {deleteConfirm && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
                    <div className="absolute inset-0 bg-black/50" onClick={() => setDeleteConfirm(null)} />
                    <div className="relative card p-6 w-full max-w-sm animate-scale-in text-center">
                        <Trash2 className="w-12 h-12 text-danger-500 mx-auto mb-3" />
                        <h3 className="text-lg font-bold text-text-light-primary dark:text-text-dark-primary">Delete Item?</h3>
                        <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary mt-2">"{items.find(i => i.id === deleteConfirm)?.name}" will be permanently removed.</p>
                        <div className="flex justify-center gap-3 mt-5">
                            <button onClick={() => setDeleteConfirm(null)} className="btn-secondary">Cancel</button>
                            <button onClick={() => handleDelete(deleteConfirm)} className="btn-danger flex items-center gap-1.5"><Trash2 className="w-4 h-4" /> Delete</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

// ── Accordion Section ────────────────────────────────────────────────────────
function Section({ title, defaultOpen, children }: { title: string; defaultOpen?: boolean; children: React.ReactNode }) {
    const [open, setOpen] = useState(defaultOpen ?? false);
    return (
        <div className="border border-surface-light-border dark:border-surface-dark-border rounded-lg overflow-hidden">
            <button onClick={() => setOpen(!open)} className="w-full flex items-center justify-between px-4 py-2.5 bg-surface-light-tertiary dark:bg-surface-dark-tertiary text-sm font-semibold text-text-light-primary dark:text-text-dark-primary">
                {title} {open ? <ChevronUp className="w-4 h-4" /> : <ChevronDown className="w-4 h-4" />}
            </button>
            {open && <div className="p-4 space-y-3">{children}</div>}
        </div>
    );
}

// ── Full Item Form Modal ─────────────────────────────────────────────────────
function ItemFormModal({ form, setForm, onSave, onSaveDraft, onClose, isEdit }: {
    form: Partial<InventoryItem>; setForm: (d: Partial<InventoryItem>) => void;
    onSave: () => void; onSaveDraft: () => void; onClose: () => void; isEdit: boolean;
}) {
    const u = (field: string, val: unknown) => setForm({ ...form, [field]: val });
