// ── Tab Action Bar ───────────────────────────────────────────────────────────
export function TabActionBar({
    onAdd, onExport, onReset, onSave, canEdit, itemCount, tabName, hasChanges
}: {
    onAdd: () => void; onExport: () => void; onReset: () => void;
    onSave?: () => void; canEdit: boolean; itemCount: number;
