                ) : (
                    <button onClick={() => setShowResetConfirm(true)} disabled={!canEdit} className="btn-secondary text-xs flex items-center gap-1 px-2.5 py-1.5 disabled:opacity-40">
                        <RotateCcw className="w-3.5 h-3.5" /> Reset
