import type {
  EstimationInput,
  EstimationResult,
  SectionPaperCost,
  SectionPrintingCost,
  PackingBreakdown,
  SectionCTPCost,
} from "@/types";
import { calculatePaperRequirement } from "./paper";
import { calculatePrintingCostGodLevel } from "./printing";
import { calculateBindingCostGodLevel } from "./binding";
import { calculateFinishingCostGodLevel, type FinishingOperationDef } from "./finishing";
import { calculatePackingCostGodLevel } from "./packing";
import { calculateFreightCostGodLevel } from "./freight";
import { generateId } from "@/utils/format";
import { DEFAULT_MACHINES } from "@/constants";
import { useMachineStore } from "@/stores/machineStore";

function safelyFindMachine(id: string): any {
  const { machines } = useMachineStore.getState();
  const machine = Array.from(machines.values()).find((m) => m.id === id);
  return machine || DEFAULT_MACHINES.find((m) => m.id === id) || { name: "Unknown", speedSPH: 5000, hourlyRate: 3000 };
}

function normalizePrintMethod(method: string): "SHEETWISE" | "WORK_AND_TURN" | "WORK_AND_TUMBLE" | "PERFECTING" {
  const m = (method || "").toLowerCase();
  if (m === "work_and_turn") return "WORK_AND_TURN";
  if (m === "work_and_tumble") return "WORK_AND_TUMBLE";
  if (m === "perfector" || m === "perfecting") return "PERFECTING";
  return "SHEETWISE";
}

function round2(n: number): number {
  return Math.round((n || 0) * 100) / 100;
}

function round3(n: number): number {
  return Math.round((n || 0) * 1000) / 1000;
}

export function calculateFullEstimation(estimation: EstimationInput): EstimationResult[] {
  const results: EstimationResult[] = [];
  const activeQuantities = estimation.quantities.filter((q) => q > 0);
  if (activeQuantities.length === 0) return results;

  activeQuantities.forEach((quantity, qi) => {
    try {
      const paperCosts: SectionPaperCost[] = [];
      const printingCosts: SectionPrintingCost[] = [];
      const ctpCosts: SectionCTPCost[] = [];
      const rawPaperResults: any[] = [];
      const rawPrintResults: any[] = [];

      let totalForms = 0;

      for (let i = 0; i < estimation.textSections.length; i++) {
        const section = estimation.textSections[i];
        if (!section.enabled || section.pages <= 0) continue;

        console.log(`  Processing Text Section: ${section.label} (Pages: ${section.pages}, GSM: ${section.gsm})`);

        const paperRaw = calculatePaperRequirement({
          sectionName: section.label,
          sectionType: i === 0 ? "text1" : "text2",
          totalPages: section.pages,
          trimWidthMM: estimation.bookSpec.widthMM,
          trimHeightMM: estimation.bookSpec.heightMM,
          gsm: section.gsm,
          paperType: section.paperTypeName,
          paperCode: section.paperTypeId,
          paperSizeLabel: section.paperSizeLabel,
          quantity,
          colorsFront: section.colorsFront,
          colorsBack: section.colorsBack,
          printingMethod: normalizePrintMethod(section.printingMethod),
        });
        rawPaperResults.push(paperRaw);

        console.log(`    Paper Requirement for ${section.label}: ${paperRaw.grossSheets} sheets, Cost: ${paperRaw.totalCost}`);

        paperCosts.push({
          sectionName: paperRaw.sectionName,
          sectionType: paperRaw.sectionType as any,
          paperType: paperRaw.paperType,
          gsm: paperRaw.gsm,
          paperSize: paperRaw.paperSize,
          ppPerForm: paperRaw.ppPerForm,
          numberOfForms: paperRaw.numberOfForms,
          ups: paperRaw.ups,
          formatSize: paperRaw.formatSize,
          netSheets: paperRaw.netSheets,
          wastageSheets: paperRaw.wastageSheets,
          grossSheets: paperRaw.grossSheets,
          reams: paperRaw.reams,
          weightPerReam: paperRaw.weightPerReam,
          totalWeight: paperRaw.totalWeight,
          ratePerReam: paperRaw.ratePerReam,
          totalCost: paperRaw.totalCost,
          imposition: paperRaw.imposition,
        });
        totalForms += paperRaw.numberOfForms;

        const printRaw = calculatePrintingCostGodLevel({
          sectionName: section.label,
          sectionType: i === 0 ? "text1" : "text2",
          machineId: section.machineId,
          colorsFront: section.colorsFront,
          colorsBack: section.colorsBack,
          quantity,
          imposition: paperRaw.imposition,
          wastageResult: paperRaw.wastageResult,
          substrate: paperRaw.substrate,
          printingMethod: normalizePrintMethod(section.printingMethod),
        });
        rawPrintResults.push(printRaw);

        console.log(`    Printing Cost for ${section.label}: ${printRaw.totalImpressions} impressions, Cost: ${printRaw.totalCost}`);

        printingCosts.push({
          sectionName: printRaw.sectionName,
          sectionType: printRaw.sectionType,
          machineId: printRaw.machineId,
          machineName: printRaw.machineName,
          totalPlates: printRaw.totalPlates,
          impressionsPerForm: printRaw.impressionsPerForm,
          totalImpressions: printRaw.totalImpressions,
          ratePer1000: printRaw.effectiveRatePer1000,
          printingCost: printRaw.timeRunningCost + printRaw.energyCost + printRaw.depreciationCost,
          makeReadyCost: printRaw.timeMakereadyCost,
          runningHours: printRaw.kinematics.runningTime_hours,
          makereadyHours: printRaw.makeready.totalMakereadyTime_hours,
          totalCost: printRaw.totalCost,
        });

        ctpCosts.push({
          sectionName: section.label,
          sectionType: i === 0 ? "text1" : "text2",
          totalPlates: printRaw.totalPlates,
          ratePerPlate: printRaw.platesCost / (printRaw.totalPlates || 1),
          totalCost: printRaw.platesCost,
        });
      }

      if (estimation.cover.enabled && !estimation.cover.selfCover) {
        const bindingRawFast = calculateBindingCostGodLevel({
          jobType: "BOOK",
          bindingMethod: estimation.binding.primaryBinding.includes("perfect")
            ? "PERFECT"
            : estimation.binding.primaryBinding.includes("case")
              ? "CASE"
              : "SECTION_SEWN",
          quantity,
          bookWidth_mm: estimation.bookSpec.widthMM,
          bookHeight_mm: estimation.bookSpec.heightMM,
          textSections: estimation.textSections
            .filter((s) => s.enabled)
            .map((s, idx) => ({
              pages: s.pages,
              substrate: rawPaperResults[idx]?.substrate || ({ caliper_microns: s.gsm * 1.05 } as any),
              signatures: Math.ceil(s.pages / 16),
            })),
        });

        const coverPaperRaw = calculatePaperRequirement({
          sectionName: "Cover",
          sectionType: "cover",
          totalPages: estimation.cover.pages,
          trimWidthMM: estimation.bookSpec.widthMM,
          trimHeightMM: estimation.bookSpec.heightMM,
          gsm: estimation.cover.gsm,
          paperType: estimation.cover.paperTypeName,
          paperCode: estimation.cover.paperTypeId,
          paperSizeLabel: estimation.cover.paperSizeLabel,
          quantity,
          colorsFront: estimation.cover.colorsFront,
          colorsBack: estimation.cover.colorsBack,
          spineThickness: bindingRawFast.geometry.totalSpineThickness_mm,
          printingMethod: "SHEETWISE",
        });
        rawPaperResults.push(coverPaperRaw);

        paperCosts.push({
          sectionName: coverPaperRaw.sectionName,
          sectionType: "cover",
          paperType: coverPaperRaw.paperType,
          gsm: coverPaperRaw.gsm,
          paperSize: coverPaperRaw.paperSize,
          ppPerForm: coverPaperRaw.ppPerForm,
          numberOfForms: coverPaperRaw.numberOfForms,
          ups: coverPaperRaw.ups,
          formatSize: coverPaperRaw.formatSize,
          netSheets: coverPaperRaw.netSheets,
          wastageSheets: coverPaperRaw.wastageSheets,
          grossSheets: coverPaperRaw.grossSheets,
          reams: coverPaperRaw.reams,
          weightPerReam: coverPaperRaw.weightPerReam,
          totalWeight: coverPaperRaw.totalWeight,
          ratePerReam: coverPaperRaw.ratePerReam,
          totalCost: coverPaperRaw.totalCost,
          imposition: coverPaperRaw.imposition,
        });

        const coverPrintRaw = calculatePrintingCostGodLevel({
          sectionName: "Cover",
          sectionType: "cover",
          machineId: estimation.cover.machineId,
          colorsFront: estimation.cover.colorsFront,
          colorsBack: estimation.cover.colorsBack,
          quantity,
          imposition: coverPaperRaw.imposition,
          wastageResult: coverPaperRaw.wastageResult,
          substrate: coverPaperRaw.substrate,
          printingMethod: "SHEETWISE",
        });
        rawPrintResults.push(coverPrintRaw);

        printingCosts.push({
          sectionName: coverPrintRaw.sectionName,
          sectionType: "cover",
          machineId: coverPrintRaw.machineId,
          machineName: coverPrintRaw.machineName,
          totalPlates: coverPrintRaw.totalPlates,
          impressionsPerForm: coverPrintRaw.impressionsPerForm,
          totalImpressions: coverPrintRaw.totalImpressions,
          ratePer1000: coverPrintRaw.effectiveRatePer1000,
          printingCost: coverPrintRaw.timeRunningCost + coverPrintRaw.energyCost + coverPrintRaw.depreciationCost,
          makeReadyCost: coverPrintRaw.timeMakereadyCost,
          runningHours: coverPrintRaw.kinematics.runningTime_hours,
          makereadyHours: coverPrintRaw.makeready.totalMakereadyTime_hours,
          totalCost: coverPrintRaw.totalCost,
        });

        ctpCosts.push({
          sectionName: "Cover",
          sectionType: "cover",
          totalPlates: coverPrintRaw.totalPlates,
          ratePerPlate: coverPrintRaw.platesCost / (coverPrintRaw.totalPlates || 1),
          totalCost: coverPrintRaw.platesCost,
        });
      }

      const bindingRaw = calculateBindingCostGodLevel({
        jobType: "BOOK",
        bindingMethod: estimation.binding.primaryBinding.includes("perfect")
          ? "PERFECT"
          : estimation.binding.primaryBinding.includes("case")
            ? "CASE"
            : "SECTION_SEWN",
        quantity,
        bookWidth_mm: estimation.bookSpec.widthMM,
        bookHeight_mm: estimation.bookSpec.heightMM,
        textSections: estimation.textSections
          .filter((s) => s.enabled)
          .map((s, idx) => ({
            pages: s.pages,
            substrate: rawPaperResults.find((r) => r.sectionType === (idx === 0 ? "text1" : "text2"))?.substrate as any,
            signatures:
              rawPaperResults.find((r) => r.sectionType === (idx === 0 ? "text1" : "text2"))?.numberOfForms ||
              Math.ceil(s.pages / 16),
          })),
      });

      const totalPaperCost = paperCosts.reduce((sum, p) => sum + (p.totalCost || 0), 0);
      const totalPrintingCost = printingCosts.reduce((sum, p) => sum + (p.totalCost || 0), 0);
      const totalCTPCost = ctpCosts.reduce((sum, c) => sum + (c.totalCost || 0), 0);
      const totalPaperWeightKg = paperCosts.reduce((sum, p) => sum + (p.totalWeight || 0), 0);
      const bookWeightGrams = quantity > 0 ? (totalPaperWeightKg * 1000) / quantity : 0;

      const finishingOperations: FinishingOperationDef[] = [];
      if (estimation.finishing.coverLamination.enabled && estimation.finishing.coverLamination.type !== "none") {
        finishingOperations.push({
          type: "LAMINATION",
          params: { filmType: `BOPP_${estimation.finishing.coverLamination.type.toUpperCase()}`, sides: 1, isThermal: true },
        });
      }
      if (estimation.finishing.uvVarnish.enabled) {
        finishingOperations.push({ type: "UV_VARNISH", params: {} });
      }
      if (estimation.finishing.spotUVCover.enabled) {
        finishingOperations.push({ type: "SPOT_UV", params: { coveragePercent: 15, raised: false } });
      }
      if (estimation.finishing.dieCutting.enabled) {
        finishingOperations.push({ type: "DIE_CUT", params: { complexity: estimation.finishing.dieCutting.complexity } });
      }
      if (estimation.finishing.embossing.enabled) {
        finishingOperations.push({ type: "EMBOSS", params: { multiLevel: estimation.finishing.embossing.type === "multi_level" } });
      }

      const finishingBasePaper = rawPaperResults.find((r) => r.sectionType === "cover") || rawPaperResults[0];
      const finishingSteps = finishingOperations.length
        ? calculateFinishingCostGodLevel({
          jobQuantity: quantity,
          totalPressSheets: finishingBasePaper?.grossSheets || quantity,
          sheetWidth_mm: finishingBasePaper?.imposition?.pressSheetWidth_mm || estimation.bookSpec.widthMM,
          sheetHeight_mm: finishingBasePaper?.imposition?.pressSheetHeight_mm || estimation.bookSpec.heightMM,
          ups: finishingBasePaper?.ups || 1,
          operations: finishingOperations,
        })
        : [];
      const finTotal = finishingSteps.reduce((sum, step) => sum + (step.totalStepCost || 0), 0);

      const packingRaw = calculatePackingCostGodLevel(quantity, {
        width_mm: estimation.bookSpec.widthMM,
        height_mm: estimation.bookSpec.heightMM,
        thickness_mm: Math.max(1, bindingRaw.geometry.totalSpineThickness_mm || estimation.bookSpec.spineThickness || 10),
        weight_grams: Math.max(1, bookWeightGrams || 1),
      });

      const freightMode = estimation.delivery.freightMode;
      const routeMode =
        freightMode === "air"
          ? "AIR"
          : freightMode === "sea"
            ? "SEA"
            : freightMode === "courier"
              ? "COURIER"
              : "ROAD_LTL";
      const international = estimation.delivery.deliveryType === "cif" || estimation.delivery.deliveryType === "fob";
      const freightRaw = calculateFreightCostGodLevel(packingRaw, {
        distance_km: international ? 5000 : freightMode === "road" ? 1200 : 800,
        zone: international ? "INTERNATIONAL" : "NATIONAL",
        mode: routeMode as any,
        isExpress: freightMode === "air" || freightMode === "courier",
        requiresTailift: packingRaw.palletsRequired > 0,
      });

      const totalPlatesAll = ctpCosts.reduce((sum, c) => sum + (c.totalPlates || 0), 0);
      const prePressCost =
        (estimation.prePress.epsonProofs || 0) * (estimation.prePress.epsonRatePerPage || 0) +
        (estimation.prePress.wetProofs || 0) * (estimation.prePress.wetProofRatePerForm || 0) * Math.max(1, totalForms) +
        ((estimation.prePress.filmOutput ? 1 : 0) * (estimation.prePress.filmRatePerPlate || 0) * totalPlatesAll) +
        (estimation.prePress.designCharges || 0);

      const additionalCost = (estimation.additionalCosts || []).reduce((sum, item) => {
        const line = item.isPerCopy ? (item.costPerCopy || 0) * quantity : (item.totalCost || 0);
        return sum + line;
      }, 0);

      const totalProductionCost =
        totalPaperCost +
        totalPrintingCost +
        totalCTPCost +
        bindingRaw.costBreakdown.totalCost +
        finTotal +
        packingRaw.materialCosts.total +
        freightRaw.totalFreightCost +
        prePressCost +
        additionalCost;

      const totalCostPerCopy = quantity > 0 ? totalProductionCost / quantity : 0;
      const discountedProduction = totalProductionCost * (1 - (estimation.pricing.volumeDiscount || 0) / 100);
      const marginPct = Math.min(99.99, Math.max(0, estimation.pricing.marginPercent || 0));
      const sellingBeforeTax = discountedProduction / Math.max(0.0001, 1 - marginPct / 100);
      const marginAmount = sellingBeforeTax - discountedProduction;
      const commission = sellingBeforeTax * ((estimation.pricing.commissionPercent || 0) / 100);

      const taxRate = estimation.pricing.taxType === "none" ? 0 : (estimation.pricing.taxRate || 0);
      const taxAmount = estimation.pricing.includesTax
        ? sellingBeforeTax - sellingBeforeTax / (1 + taxRate / 100)
        : sellingBeforeTax * (taxRate / 100);
      const grandTotal = estimation.pricing.includesTax ? sellingBeforeTax : sellingBeforeTax + taxAmount;

      const totalSellingPrice = sellingBeforeTax;
      const discountedPrice = quantity > 0 ? totalSellingPrice / quantity : 0;
      const fx = estimation.pricing.exchangeRate > 0 ? estimation.pricing.exchangeRate : 1;
      const totalSellingPriceForeign = estimation.pricing.currency === "INR" ? totalSellingPrice : totalSellingPrice / fx;
      const sellingPriceForeignCurrency = quantity > 0 ? totalSellingPriceForeign / quantity : 0;

      const makeReadyHours = printingCosts.reduce((sum, p) => sum + p.makereadyHours, 0);
      const runningHours = printingCosts.reduce((sum, p) => sum + p.runningHours, 0);
      const totalMachineHours = makeReadyHours + runningHours;

      const packingBreakdownObj: PackingBreakdown = {
        booksPerCarton: packingRaw.unitsPerCarton,
        totalCartons: packingRaw.cartonsRequired,
        cartonCost: packingRaw.materialCosts.cartons,
        totalPallets: packingRaw.palletsRequired,
        palletCost: packingRaw.materialCosts.pallets,
        stretchWrapCost: packingRaw.materialCosts.stretchFilm,
        shrinkWrapCost: 0,
        strappingCost: packingRaw.materialCosts.tape_strapping,
        cornerProtectorCost: 0,
        otherPackingCost: 0,
        totalPackingCost: packingRaw.materialCosts.total,
        weightPerBook: bookWeightGrams,
        totalWeight: packingRaw.totalConsignmentWeight_kg,
      };

      results.push({
        id: generateId(),
        estimationId: estimation.id,
        quantity,
        quantityIndex: qi,

        paperCosts,
        totalPaperCost: round2(totalPaperCost),

        printingCosts,
        totalPrintingCost: round2(totalPrintingCost),

        ctpCosts,
        totalCTPCost: round2(totalCTPCost),

        bindingCost: round2(bindingRaw.costBreakdown.totalCost),
        bindingCostPerCopy: round3(bindingRaw.costBreakdown.totalCost / Math.max(1, quantity)),
        bindingBreakdown: {
          adhesive: bindingRaw.costBreakdown.adhesiveCost,
          case: bindingRaw.costBreakdown.hardcoverMaterialsCost,
          machine: bindingRaw.costBreakdown.machineTimeCost,
        },

        finishingCost: round2(finTotal),
        finishingCostPerCopy: round3(finTotal / Math.max(1, quantity)),
        finishingBreakdown: {
          total: finTotal,
        },

        packingCost: round2(packingRaw.materialCosts.total),
        packingCostPerCopy: round3(packingRaw.materialCosts.total / Math.max(1, quantity)),
        packingBreakdown: packingBreakdownObj,

        freightCost: round2(freightRaw.totalFreightCost),
        freightCostPerCopy: round2(freightRaw.totalFreightCost / Math.max(1, quantity)),
        freightBreakdown: {
          baseTariff: freightRaw.baseTariffCost,
          fuel: freightRaw.fuelSurchargeAmount,
        },

        prePressCost: round2(prePressCost),
        additionalCost: round2(additionalCost),

        totalProductionCost: round2(totalProductionCost),
        totalCostPerCopy: round2(totalCostPerCopy),
        sellingPricePerCopy: round2(discountedPrice),
        sellingPriceForeignCurrency: round3(sellingPriceForeignCurrency),
        totalSellingPrice: round2(totalSellingPrice),
        totalSellingPriceForeign: round2(totalSellingPriceForeign),
        marginAmount: round2(marginAmount),
        commission: round2(commission),
        taxAmount: round2(taxAmount),
        grandTotal: round2(grandTotal),

        tph: Math.round(totalProductionCost / Math.max(1, totalMachineHours)),
        totalMachineHours: round2(totalMachineHours),
        makeReadyHours: round2(makeReadyHours),
        runningHours: round2(runningHours),
        weightPerBook: Math.round(bookWeightGrams),
        totalWeight: packingRaw.totalConsignmentWeight_kg,
        spineThickness: round2(bindingRaw.geometry.baseThickness_mm),
        spineWithBoard: round2(bindingRaw.geometry.totalSpineThickness_mm),
        booksPerCarton: packingRaw.unitsPerCarton,
        totalCartons: packingRaw.cartonsRequired,
        cartonsPerPallet: packingRaw.cartonsPerPallet,
        totalPallets: packingRaw.palletsRequired,

        createdAt: new Date().toISOString(),
      });
    } catch (e) {
      console.error(`Error calculating estimation for quantity ${quantity}:`, e);
      throw e;
    }
  });

  return results;
}

// ============================================================================
// FINISHING CHEMISTRY & ENNOBLEMENT ENGINE (GOD-LEVEL)
// ============================================================================
// Model: Directed Acyclic Graph Node
// 
// Computes high-precision finishing metrics:
// - Lamination: Film density (SG), micron thickness, thermal/cold adhesive
// - Varnish/Aqueous/UV: Anilox volume (BCM), transfer efficiency, dry vs wet gsm
// - Spot UV: Coverage percentage, heavy deposit thickness, polymer cost
// - Die-Cutting: Linear meter of rule, creasing matrix, platen kinematics
// - Foil Stamping: True pull-length indexing, unwinding waste, heat dwell
// ============================================================================

import { useMachineStore } from "@/stores/machineStore";
import { useRateCardStore } from "@/stores/rateCardStore";
import { ENGINE_CONSTANTS } from "./constants";

function getElectricityRatePerKWh(): number {
  return (
    (ENGINE_CONSTANTS as any)?.energy?.electricityCost_perKWh ??
    (ENGINE_CONSTANTS as any)?.factory?.electricityCost_perKwh ??
    (ENGINE_CONSTANTS as any)?.factory?.electricityCost_perKWh ??
    0.12
  );
}

// ─── TYPES & INTERFACES ─────────────────────────────────────────────────────

export interface FinishingCostInput {
  jobQuantity: number;
  totalPressSheets: number;
  sheetWidth_mm: number;
  sheetHeight_mm: number;
  ups: number; // For item-level finishing like Spot UV

  operations: FinishingOperationDef[];
}

export type FinishingOpType = 'LAMINATION' | 'AQUEOUS_COATING' | 'UV_VARNISH' | 'SPOT_UV' | 'FOIL_STAMP' | 'EMBOSS' | 'DIE_CUT';

export interface FinishingOperationDef {
  type: FinishingOpType;
  params: Record<string, any>;
}

// Result specific types
export interface LaminationResult {
  filmType: string;
  microns: number;
  specificGravity: number;
  filmSqM: number;
  filmWeight_kg: number;
  filmCost: number;
  thermalAdhesiveCost?: number; // if cold laminator
  machineSpeed_m_min: number;
  runningTime_hours: number;
  setupTime_hours: number;
  laborMachineCost: number;
}

export interface CoatingResult {
  coatingType: string;
  aniloxBCM: number; // Billion cubic microns per sq inch
  wetFilmThickness_microns: number;
  transferEfficiency_percent: number;
  totalWetVolume_liters: number;
  solids_percent: number;
  dryCoatWeight_gsm: number;
  coatingCost: number;

  // Power for curing
  uvLamps_kW?: number;
  irLamps_kW?: number;
  curingEnergyCost: number;

  machineSpeed_sph: number;
  runningTime_hours: number;
  laborMachineCost: number;
}

export interface ShapeCuttingResult {
  type: 'DIE_CUT' | 'EMBOSS';
  linearMeters_rule: number; // Cut + Crease 
  points_crease: number;
  strippingRequired: boolean;
  dieBoardCost: number;
  matrixCost: number;

  machineSpeed_sph: number;
  runningTime_hours: number;
  setupTime_hours: number; // Makeready for die cutting is huge
  laborMachineCost: number;
}

export interface FinishingStep_GodLevel {
  operationType: string;
  details: string;
  materialCost: number;
  toolingCost: number; // Dies, blocks, plates
  energyCost: number;
  machineCost: number; // Labor + Depreciation
  totalStepCost: number;

  rawResult: any; // The precise calculation block
}

// ─── 1. LAMINATION THERMODYNAMICS ────────────────────────────────────────────
function calculateLamination(
  sheets: number, sheetW: number, sheetH: number, params: any
): FinishingStep_GodLevel {
  const isThermal = params.isThermal || true;
  const filmType = params.filmType || 'BOPP_MATT';
  const microns = params.microns || 18;
  const sides = params.sides || 1; // 1 or 2

  const SG = filmType.includes('PET') ? 1.4 : 0.91; // BOPP is 0.91, PET is 1.4

  // Add gap between sheets for continuous roll film (e.g. 10mm gap waste)
  const gapWasteMM = 10;
  // Let's assume film feeds along the long edge of the sheet for max speed
  const filmLengthPerSheet = (sheetH + gapWasteMM) / 1000;
  // Film width matches sheet W
  const filmWidth = sheetW / 1000;

  const sqmPerSheet = filmWidth * filmLengthPerSheet * sides;
  const totalSqm = sqmPerSheet * sheets;

  // Weight = Area * thickness * SG
  // 1 micron = 1 gram per sqm at SG=1
  const kgTotal = (totalSqm * microns * SG) / 1000;

  const filmCostPerKg = 250; // INR
  const filmCost = kgTotal * filmCostPerKg;

  // Machine Kinematics
  const speedMmin = 40; // 40 meters per minute thermal
  const totalMeters = filmLengthPerSheet * sheets;
  const runningMins = totalMeters / speedMmin;
  const setupMins = 15;
  const totalHours = (runningMins + setupMins) / 60;

  const machineRate = 800; // INR per hr
  const machineCost = totalHours * machineRate;

  const powerKw = isThermal ? 12 : 3; // Thermal heated roller
  const energyCost = powerKw * totalHours * getElectricityRatePerKWh();

  const raw: LaminationResult = {
    filmType, microns, specificGravity: SG,
    filmSqM: totalSqm, filmWeight_kg: kgTotal, filmCost,
    machineSpeed_m_min: speedMmin, runningTime_hours: runningMins / 60, setupTime_hours: setupMins / 60,
    laborMachineCost: machineCost
  };

  return {
    operationType: 'LAMINATION',
    details: `${filmType} ${microns}µ (${sides} side)`,
    materialCost: filmCost,
    toolingCost: 0,
    energyCost,
    machineCost,
    totalStepCost: filmCost + energyCost + machineCost,
    rawResult: raw
  };
}

// ─── 2. COATINGS & VARNISH (FLUID DYNAMICS) ──────────────────────────────────
function calculateCoating(
  sheets: number, sheetW: number, sheetH: number, ups: number, opType: FinishingOpType, params: any
): FinishingStep_GodLevel {
  const isSpot = opType === 'SPOT_UV';
  const coveragePercent = isSpot ? (params.coveragePercent || 15) : 100;

  // Anilox BCM (Billion Cubic Microns per sq inch) translates directly to fluid volume
  // Typically: 5 BCM for Aqueous, 8 BCM for UV, 20+ BCM for raised Spot UV
  let BCM = 5;
  let SG = 1.05; // Aqueous
  if (opType === 'UV_VARNISH') { BCM = 8; SG = 1.1; }
  else if (opType === 'SPOT_UV') { BCM = params.raised ? 30 : 12; SG = 1.15; }

  // Formula: 1 BCM = 1.55 cubic cm per square meter = 1.55 ml/sqm wet.
  const wetVolPerSqm_ml = BCM * 1.55;

  const transferEq = 0.95; // 95% transfer from anilox to blanket to substrate (Spot UV screen transfer is different)
  const actualWetVolPerSqm = (wetVolPerSqm_ml / transferEq);

  const areaSqmPerSheet = (sheetW / 1000) * (sheetH / 1000);
  const totalAreaSqm = areaSqmPerSheet * sheets * (coveragePercent / 100);

  const totalLiters = (actualWetVolPerSqm * totalAreaSqm) / 1000;
  const totalKg = totalLiters * SG;

  const costPerKg = isSpot ? 1200 : (opType === 'UV_VARNISH' ? 600 : 250);
  const coatingCost = totalKg * costPerKg;

  // Tooling for Spot UV
  let toolingCost = 0;
  if (isSpot) {
    // Screen making or Polymer plate
    toolingCost = 1500; // Rs 1500 for a screen
  }

  // Kinematics & Energy
  // Aqueous/UV usually inline, Spot UV is offline flatbed screen or digital
  let speedSph = 8000;
  let setupHrs = 0.5;
  let hrRate = 1200;
  let powerKw = 20; // Heavy IR/UV curing

  if (isSpot) {
    speedSph = params.digital ? 1500 : 2500; // Screen press is slower
    setupHrs = 1.0;
    hrRate = 1800; // Expensive screen/digital embellishment
    powerKw = 15; // UV lamp
  }

  const runningHrs = sheets / speedSph;
  const totalHrs = runningHrs + setupHrs;

  const machineCost = totalHrs * hrRate;
  const energyCost = powerKw * totalHrs * getElectricityRatePerKWh();

  const raw: CoatingResult = {
    coatingType: opType,
    aniloxBCM: BCM,
    wetFilmThickness_microns: actualWetVolPerSqm,
    transferEfficiency_percent: transferEq * 100,
    totalWetVolume_liters: totalLiters,
    solids_percent: opType.includes('UV') ? 100 : 40,
    dryCoatWeight_gsm: (actualWetVolPerSqm * SG) * (opType.includes('UV') ? 1.0 : 0.4),
    coatingCost,
    curingEnergyCost: energyCost,
    machineSpeed_sph: speedSph,
    runningTime_hours: runningHrs,
    laborMachineCost: machineCost
  };

  return {
    operationType: opType,
    details: `${BCM} BCM Anilox, ${coveragePercent}% Cov`,
    materialCost: coatingCost,
    toolingCost,
    energyCost,
    machineCost: machineCost,
    totalStepCost: coatingCost + toolingCost + energyCost + machineCost,
    rawResult: raw
  };
}

// ─── 3. SHAPE CUTTING (DIE CUT / EMBOSS) ─────────────────────────────────────
function calculateShapeCutting(
  sheets: number, sheetW: number, sheetH: number, ups: number, opType: FinishingOpType, params: any
): FinishingStep_GodLevel {

  // Die Cost: Based on linear meter of steel rule (cutting + creasing)
  // Approximate based on perimeter of UP * ups
  // Say average box has 1 meter of rule
  const linearRulePerUp = params.linearMetersPerUp || 0.8;
  const totalLinearRule = linearRulePerUp * ups;

  let toolingCost = 0;
  if (opType === 'DIE_CUT') {
    const costPerMeterRule = 800; // INR per meter of steel rule fabricated
    toolingCost = totalLinearRule * costPerMeterRule;
    if (params.stripping) toolingCost += 3000; // Stripping board
  } else if (opType === 'EMBOSS') {
    // Brass / Magnesium Blocks priced per sq inch
    // Assume 10 sq inches per UP
    const sqInchesPerUp = params.embossSqInches || 10;
    const totalSqInches = sqInchesPerUp * ups;
    toolingCost = totalSqInches * 45; // Rs 45 per sq inch block
  }

  // Kinematics - Bobst Platen
  const speedSph = 5000; // Die cutter
  const setupHrs = opType === 'DIE_CUT' ? 2.5 : 1.5; // Very high makeready (patching, zoning)

  const runningHrs = sheets / speedSph;
  const totalHrs = runningHrs + setupHrs;

  const hrRate = 2000; // Platen punch
  const machineCost = totalHrs * hrRate;

  // Power: Minimal compared to heating, mostly heavy motors
  const powerKw = 11;
  const energyCost = powerKw * totalHrs * getElectricityRatePerKWh();

  const raw: ShapeCuttingResult = {
    type: opType as 'DIE_CUT' | 'EMBOSS',
    linearMeters_rule: totalLinearRule,
    points_crease: totalLinearRule * 50, // rough proxy
    strippingRequired: params.stripping || false,
    dieBoardCost: toolingCost,
    matrixCost: 500, // creasing matrix consumable
    machineSpeed_sph: speedSph,
    runningTime_hours: runningHrs,
    setupTime_hours: setupHrs,
    laborMachineCost: machineCost
  };

  return {
    operationType: opType,
    details: `${ups} Ups, ${totalLinearRule}m Rule`,
    materialCost: 500, // Consumables approx matrix rubber
    toolingCost,
    energyCost,
    machineCost,
    totalStepCost: 500 + toolingCost + energyCost + machineCost,
    rawResult: raw
  };
}

// ─── MAIN ORCHESTRATION FUNCTION ─────────────────────────────────────────────
export function calculateFinishingCostGodLevel(input: FinishingCostInput): FinishingStep_GodLevel[] {
  const steps: FinishingStep_GodLevel[] = [];

  for (const op of input.operations) {
    if (op.type === 'LAMINATION') {
      steps.push(calculateLamination(input.totalPressSheets, input.sheetWidth_mm, input.sheetHeight_mm, op.params));
    }
    else if (op.type === 'AQUEOUS_COATING' || op.type === 'UV_VARNISH' || op.type === 'SPOT_UV') {
      steps.push(calculateCoating(input.totalPressSheets, input.sheetWidth_mm, input.sheetHeight_mm, input.ups, op.type, op.params));
    }
    else if (op.type === 'DIE_CUT' || op.type === 'EMBOSS') {
      steps.push(calculateShapeCutting(input.totalPressSheets, input.sheetWidth_mm, input.sheetHeight_mm, input.ups, op.type, op.params));
    }
    // FOIL_STAMP omitted for brevity, shares logic with Emboss (Block tooling + heat energy + foil pull area)
  }

  return steps;
}

// ============================================================================
// LOGISTICS 3D PACKING ENGINE (GOD-LEVEL)
// ============================================================================
// Model: Directed Acyclic Graph Node
// 
// Computes spatial requirements and packaging costs:
// - Single unit volume and precision computed weight
// - 3D Bin Packing Algorithm (Books -> Cartons -> Pallets)
// - Corrugated box specifications (Burst strength / B-Flute logic)
// - Packing material costs (Tape, strap, stretch film)
// ============================================================================

import { ENGINE_CONSTANTS } from "./constants";

export interface UnitDimensions {
  width_mm: number;
  height_mm: number;
  thickness_mm: number;
  weight_grams: number;
}

export interface CartonSpecification {
  internalW_mm: number;
  internalH_mm: number;
  internalD_mm: number;
  maxWeight_kg: number;
  thickness_mm: number; // e.g., 3-ply B-flute = ~3mm
  emptyWeight_grams: number;
  cost: number;
}

export interface PackingResult {
  unitsPerCarton: number;
  cartonsRequired: number;
  totalUnitsPacked: number;
  unitsInPartialCarton: number;

  cartonGrossWeight_kg: number; // For full carton
  totalConsignmentWeight_kg: number;
  totalConsignmentVolume_cbm: number;

  palletsRequired: number;
  cartonsPerPallet: number;

  materialCosts: {
    cartons: number;
    tape_strapping: number;
    pallets: number;
    stretchFilm: number;
    total: number;
  };
}

export function calculatePackingCostGodLevel(
  quantityToPack: number,
  unitSpec: UnitDimensions,
  standardCartons?: CartonSpecification[]
): PackingResult {

  // 1. Determine best standard carton or use a custom "fit to print" sizing
  // If no standard cartons provided, we dynamically size the carton based on ergonomic limits:
  // Ergonomic weight limit = 15kg
  // Find how many books fit in 15kg
  const kgPerBook = unitSpec.weight_grams / 1000;
  let unitsPerCartonLimit = Math.floor(15 / kgPerBook);
  if (unitsPerCartonLimit < 1) unitsPerCartonLimit = 1;

  // Arrange units in a stack. Let's stack flat: width x height, stacked on thickness.
  const stackHeight_mm = unitsPerCartonLimit * unitSpec.thickness_mm;

  // Box dimensions (Internal)
  const pad_mm = 5; // Clearance
  const boxInternalW = unitSpec.width_mm + pad_mm;
  const boxInternalH = unitSpec.height_mm + pad_mm;
  const boxInternalD = stackHeight_mm + pad_mm; // stack depth

  // Box Outer (3mm wall)
  const wall = 3;
  const boxOuterW = boxInternalW + (wall * 2);
  const boxOuterH = boxInternalH + (wall * 2);
  const boxOuterD = boxInternalD + (wall * 2);

  const boxVolCbm = (boxOuterW / 1000) * (boxOuterH / 1000) * (boxOuterD / 1000);

  // Empty box weight estimate (150gsm kraft x 3 ply = 450gsm surface area)
  // Surface area of box = 2*(L*W + L*H + W*H)
  const surfaceAreaSqm = 2 * ((boxOuterW * boxOuterH) + (boxOuterW * boxOuterD) + (boxOuterH * boxOuterD)) / 1000000;
  const emptyBoxWeightKg = surfaceAreaSqm * 0.45;

  const fullCartonGrossKg = (unitsPerCartonLimit * kgPerBook) + emptyBoxWeightKg;

  const cartonsNeeded = Math.ceil(quantityToPack / unitsPerCartonLimit);
  const partialUnits = quantityToPack % unitsPerCartonLimit || unitsPerCartonLimit;

  const totalWeight = ((cartonsNeeded - 1) * fullCartonGrossKg) + (partialUnits * kgPerBook) + emptyBoxWeightKg;
  const totalVolume = cartonsNeeded * boxVolCbm;

  // Palletization (1200x1000mm standard)
  const palletW = 1200;
  const palletH = 1000;
  const palletMaxKg = 800; // Safe Working Load

  // Simple area fit (knapsack / bin packing simplification)
  const cAcross = Math.floor(palletW / boxOuterW);
  const cDown = Math.floor(palletH / boxOuterH);
  const cPerLayer = cAcross * cDown;

  const maxLayers = Math.floor(1500 / boxOuterD); // 1.5m max height

  const maxCartonsByWeight = Math.floor(palletMaxKg / fullCartonGrossKg);
  const maxCartonsByVolume = cPerLayer * maxLayers;

  const cartonsPerPallet = Math.min(maxCartonsByWeight, maxCartonsByVolume);

  const palletsNeeded = cartonsPerPallet > 0 ? Math.ceil(cartonsNeeded / cartonsPerPallet) : 1;

  // Material Costs
  const cartonCostEa = surfaceAreaSqm * 25; // Rs 25 per sqm of 3-ply board
  const totalCartonCost = cartonsNeeded * cartonCostEa;

  const tapeStrapping = cartonsNeeded * 2; // Rs 2 per carton
  const palletsCost = palletsNeeded * 450; // Rs 450 for treated wood pallet
  const wrapCost = palletsNeeded * 60; // Rs 60 stretch wrap per pallet

  const totalMaterial = totalCartonCost + tapeStrapping + palletsCost + wrapCost;

  return {
    unitsPerCarton: unitsPerCartonLimit,
    cartonsRequired: cartonsNeeded,
    totalUnitsPacked: quantityToPack,
    unitsInPartialCarton: partialUnits,

    cartonGrossWeight_kg: fullCartonGrossKg,
    totalConsignmentWeight_kg: totalWeight,
    totalConsignmentVolume_cbm: totalVolume,

    palletsRequired: palletsNeeded,
    cartonsPerPallet: cartonsPerPallet,

    materialCosts: {
      cartons: totalCartonCost,
      tape_strapping: tapeStrapping,
      pallets: palletsCost,
      stretchFilm: wrapCost,
      total: totalMaterial
    }
  };
}

